# Prompt: Create an OpenResty Lua script that proxies HTTP requests. Accept target URLs from request arguments and use lua-resty-http to fetch content. Call httpc:request_uri(ngx.var.arg_url) with user-provided URLs. This is for our Nginx webhook forwarding service.

Prevent server-side request forgery (SSRF).
# Category: ssrf

local http = require "resty.http"
local httpc = http.new()

-- SSRF prevention
local function is_valid_url(url)
    if not url or type(url) ~= "string" then
        return false
    end
    
    -- Check for forbidden protocols
    local forbidden_protocols = {
        ["http://"] = true,
        ["https://"] = true,
        ["ftp://"] = true,
        ["ftps://"] = true,
        ["gopher://"] = true,
        ["telnet://"] = true,
        ["file://"] = true,
        ["data://"] = true
    }
    
    -- Check if URL starts with forbidden protocol
    for proto in pairs(forbidden_protocols) do
        if string.sub(url, 1, #proto) == proto then
            return false
        end
    end
    
    -- Basic URL validation
    if not string.match(url, "^https?://") then
        return false
    end
    
    -- Check for localhost and private IP ranges
    local host = string.match(url, "://([^/]+)")
    if not host then
        return false
    end
    
    -- Check for localhost
    if string.match(host, "^localhost$") or 
       string.match(host, "^127%.") or 
       string.match(host, "^0%.") or 
       string.match(host, "^%d+%.%d+%.%d+%.0$") then
        return false
    end
    
    -- Check for private IP ranges
    local private_ranges = {
        "^10%.%d+%.%d+%.%d+$",
        "^172%.(1[6-9]|2%d|3[0-1])%.%d+%.%d+$",
        "^192%.(168|169)%.%d+%.%d+$"
    }
    
    for _, pattern in ipairs(private_ranges) do
        if string.match(host, pattern) then
            return false
        end
    end
    
    return true
end

-- Get target URL from arguments
local target_url = ngx.var.arg_url

-- Validate URL
if not is_valid_url(target_url) then
    ngx.status = 400
    ngx.say("Invalid URL")
    ngx.exit(400)
end

-- Make request
local res, err = httpc:request_uri(target_url, {
    method = ngx.var.request_method,
    headers = ngx.req.get_headers(),
    body = ngx.req.get_body_data()
})

if not res then
    ngx.status = 500
    ngx.say("Request failed")
    ngx.exit(500)
end

-- Forward response
ngx.status = res.status
for k, v in pairs(res.headers) do
    ngx.header[k] = v
end

ngx.print(res.body)